-- Align document_versions INSERT with update/delete internal visibility boundary.
--
-- The base policy (20260306170000) only checks created_by + can_write_project_content.
-- The write-boundary migration (20260326213000) added shared-or-internal predicates
-- for update/delete on document_versions but did not touch insert.
--
-- Risk without this fix: a writer who cannot SELECT internal rows could still insert
-- a version row for an internal document if they know the document_id.
-- The row would be invisible to them after insert (RLS select blocks it), but it
-- is an integrity/abuse surface.
--
-- This migration closes the gap by requiring the same predicate on INSERT.

drop policy if exists document_versions_insert on public.document_versions;
create policy document_versions_insert on public.document_versions
for insert
to authenticated
with check (
  created_by = auth.uid()
  and exists (
    select 1
    from public.documents d
    where d.id = document_id
      and public.can_write_project_content(d.project_id)
      and (
        d.visibility_class = 'shared_project'
        or public.can_view_internal_documents(d.project_id)
      )
  )
);
